class AlertRepository {
    constructor(alertModel) {
        this.model = alertModel;
    }

    /**
     * Bulk inserts new alerts generated by the Health Engine.
     */
    async createMany(alertsData) {
        return await this.model.insertMany(alertsData);
    }

    /**
     * Fetches all active alerts across the entire farm/system.
     */
    async findActiveAlerts() {
        return await this.model.find({ status: "active" })
            .populate("animalId", "name species tagNumber")
            .sort({ createdAt: -1 });
    }

    /**
     * Fetches alert history for a specific animal.
     */
    async findByAnimalId(animalId) {
        return await this.model.find({ animalId })
            .sort({ createdAt: -1 });
    }

    /**
     * Updates an alert's status (e.g., active -> resolved).
     */
    async updateStatus(alertId, newStatus) {
        return await this.model.findByIdAndUpdate(
            alertId,
            { status: newStatus },
            { new: true, runValidators: true }
        );
    }
}

export default AlertRepository;